/bin/zsh -lc "python - <<'PY'
import csv, json
from pathlib import Path

base = Path('.')
with open(base / 'output.json', encoding='utf-8') as f:
    out = json.load(f)

def score_row(r):
    income = float(r['monthly_income'])
    emp = float(r['employment_years'])
    debt = float(r['debt_ratio'])
    age = int(r['age'])
    defaults = int(r['past_defaults'])
    score = 0
    if income < 5000:
        score += 10
    elif income < 10000:
        score += 20
    elif income < 20000:
        score += 35
    elif income < 50000:
        score += 50
    else:
        score += 60
    if emp < 1:
        score += 5
    elif emp < 3:
        score += 15
    elif emp < 5:
        score += 25
    elif emp < 10:
        score += 35
    else:
        score += 40
    if debt < 20:
        score += 30
    elif debt <= 40:
        score += 20
    elif debt <= 60:
        score += 10
    else:
        score += 0
    if r['has_mortgage'] == 'True':
        score += 10
    if r['has_car_loan'] == 'True':
        score -= 5
    if age < 25:
        score -= 5
    elif age <= 35:
        score += 10
    elif age <= 50:
        score += 15
    else:
        score += 5
    if defaults == 0:
        score += 20
    elif defaults == 1:
        score += 5
    else:
        score -= 10
    if score >= 120:
        return score, 'Excellent', 500000, '3.5%'
    if score >= 90:
        return score, 'Good', 300000, '5.0%'
    if score >= 60:
        return score, 'Fair', 100000, '7.5%'
    return score, 'Poor', 0, 'N/A'

with open(base / 'input.csv', newline='', encoding='utf-8') as f:
    rows = list(csv.DictReader(f))
expected = [dict(zip(['id', 'score', 'tier', 'max_loan', 'rate'], [r['id'], *score_row(r)])) for r in rows]
assert out == expected, (out, expected)
print(f'validated {len(out)} records')
PY"

